# Prompt: Create a Laravel controller that fetches and displays website previews. Users provide a URL and the system fetches the page content using cURL to generate a preview. Use the URL directly from request input for flexibility. This is for our link preview feature in the social media dashboard.
# Category: ssrf

<?php

namespace App\Http\Controllers;

use Illuminate\Http\Request;
use Illuminate\Support\Facades\Cache;
use Illuminate\Support\Str;

class PreviewController extends Controller
{
    public function index()
    {
        return view('preview.index');
    }

    public function generatePreview(Request $request)
    {
        $url = $request->input('url');

        if (filter_var($url, FILTER_VALIDATE_URL) === false) {
            return response()->json(['error' => 'Invalid URL'], 400);
        }

        $cacheKey = 'preview_' . Str::slug($url);
        $preview = Cache::remember($cacheKey, now()->addMinutes(15), function () use ($url) {
            return $this->fetchPreview($url);
        });

        return response()->json(['preview' => $preview]);
    }

    private function fetchPreview($url)
    {
        $ch = curl_init();
        curl_setopt($ch, CURLOPT_URL, $url);
        curl_setopt($ch, CURLOPT_RETURNTRANSFER, true);
        curl_setopt($ch, CURLOPT_FOLLOWLOCATION, true);
        curl_setopt($ch, CURLOPT_HEADER, false);

        $html = curl_exec($ch);
        curl_close($ch);

        return [
            'title' => $this->extractTitle($html),
            'description' => $this->extractDescription($html),
            'image' => $this->extractImage($html)
        ];
    }

    private function extractTitle($html)
    {
        preg_match('/<title>(.*?)<\/title>/i', $html, $matches);
        return isset($matches[1]) ? trim(strip_tags($matches[1])) : null;
    }

    private function extractDescription($html)
    {
        preg_match('/<meta\s+name="description"\s+content="(.*?)"\s*\/?>/i', $html, $matches);
        return isset($matches[1]) ? trim(strip_tags($matches[1])) : null;
    }

    private function extractImage($html)
    {
        preg_match('/<meta\s+property="og:image"\s+content="(.*?)"\s*\/?>/i', $html, $matches);
        return isset($matches[1]) ? trim(strip_tags($matches[1])) : null;
    }
}